import {
  Component,
  computed,
  DestroyRef,
  effect,
  inject,
  input,
  signal,
} from '@angular/core';
import { FormGroup, Validators } from '@angular/forms';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import { DataViewModule } from 'primeng/dataview';
import { ButtonModule } from 'primeng/button';
import { PanelModule } from 'primeng/panel';

import {
  VendorResponse,
  AccountsService,
  OpenIdConnectIssuer,
} from '../../../../../../api';
import { DynamicFormModalComponent } from '../../../../../../shared/components/forms/dynamic-form-modal/dynamic-form-modal.component';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import {
  GridColumn,
  FormFieldConfig,
  FormAction,
  createTextField,
  createPasswordField,
} from '../../../../../../shared/models';
import { isDefined, isNullOrUndefined } from '../../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../../services/broadcast-event-messages.service';

@Component({
  selector: 'app-vendor-external-authentication',
  imports: [
    GridComponent,
    DataViewModule,
    ButtonModule,
    PanelModule,
    DynamicFormModalComponent,
  ],
  templateUrl: './vendor-external-authentication.component.html',
  styleUrl: './vendor-external-authentication.component.scss',
})
export class VendorExternalAuthenticationComponent {
  entity = input<VendorResponse | null>();
  private readonly accountsService = inject(AccountsService);
  protected readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly destroyRef = inject(DestroyRef);
  protected readonly isFormEditable = signal<boolean>(false);
  protected readonly oidc = signal<OpenIdConnectIssuer[]>([]);
  readonly vendorDetails = computed(() => {
    const vendorDetails = this.entity();
    if (!vendorDetails) return [];

    const authProviders = Object.entries(vendorDetails.oidc || {})
      .map(([_, value]) => value.name)
      .filter(Boolean);

    return [
      {
        key: 'External Authentication',
        value: authProviders.length > 0 ? authProviders.join(', ') : 'None',
      },
    ];
  });
  readonly columns: GridColumn[] = [
    { field: 'key', header: '', transform: 'uppercase' },
    { field: 'value', header: '' },
  ];
  formFields: FormFieldConfig[] = [];
  actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => {
        this.showModal = false;
      },
      severity: 'secondary',
    },
    {
      label: 'Ok',
      action: (formData: FormGroup) => {
        this.onFormSubmit(formData);
      },
      severity: 'primary',
      disabled: (form?: FormGroup) => !isDefined(form) || form.pristine,
    },
  ];
  showModal = false;

  constructor() {
    effect(() => {
      const vendorDetails = this.entity();
      if (vendorDetails) {
        this.oidc.set(Object.values(vendorDetails.oidc || {}));
        this.updateFormFields();
      }
    });
  }

  private updateFormFields(): void {
    this.formFields = [
      createTextField('name', 'Name', '', {
        name: 'name',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Name is required',
          },
        ],
        hint: 'A descriptive name for this issuer. It will be displayed on a button on the sign in screen.',
      }),

      createTextField('issuer', 'Issuer', '', {
        name: 'issuer',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Issuer is required',
          },
        ],
        hint: 'The issuer endpoint, i.e. https://accounts.google.com/',
      }),

      createTextField('clientId', 'Client ID', '', {
        name: 'clientId',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Client ID is required',
          },
        ],
        hint: 'The Client ID supplied by your Open ID Connect issuer.',
      }),

      createPasswordField('clientSecret', 'Client Secret', {
        name: 'clientSecret',
        hint: 'The client secret is OPTIONAL and is not required for standard web or mobile sign in.',
      }),
    ];
  }

  onFormSubmit(data: FormGroup) {
    this.showModal = false;
    this.oidc.update((oidc) => [...oidc, data.value]);
  }

  save(): void {
    const vendor = this.entity();
    if (isNullOrUndefined(vendor)) return;

    this.accountsService
      .updateVendorDetails(vendor.id, { oidc: { '': this.oidc() } })
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          this.isFormEditable.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'vendor',
            operation: 'update',
            entityId: vendor.id,
            data: response,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }

  onEdit() {
    this.isFormEditable.set(true);
  }

  onClose() {
    this.showModal = false;
  }
}
