import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import {
  AccountsService,
  ClientResponse,
  EntitiesService,
} from '../../../../../../api';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import { createDropdownField } from '../../../../../../shared/models/form-field.model';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { UtilityService } from '../../../../../../core/services/utility.service';
import {
  DEFAULT_EMAIL_PROVIDER,
  DEFAULT_LIST_SIZE,
} from '../../../../../../core/models';
import {
  hasProperty,
  isDefined,
  isNullOrUndefined,
  isString,
} from '../../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../../base';

@Component({
  selector: 'app-client-notification-settings',
  imports: [GridComponent, DynamicFormComponent],
  templateUrl: './client-notification-settings.component.html',
  styleUrl: './client-notification-settings.component.scss',
})
export class ClientNotificationSettingsComponent
  extends EntitySectionBaseComponent<ClientResponse>
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly accountsService = inject(AccountsService);
  private readonly utilityService = inject(UtilityService);
  protected readonly emailProvidersLoaded = signal<boolean>(false);
  emailProviders: { label: string; value: string }[] = [
    { label: DEFAULT_EMAIL_PROVIDER.name, value: DEFAULT_EMAIL_PROVIDER.id },
  ];
  readonly clientDetails = computed(() => {
    const clientDetails = this.entity();
    if (!isDefined(clientDetails)) return [];

    const emailProvider = clientDetails.emailProvider;
    const providerName =
      isDefined(emailProvider) &&
      hasProperty(emailProvider, 'name') &&
      isString(emailProvider.name)
        ? emailProvider.name
        : 'None';

    return [
      {
        key: 'Email Provider',
        value: providerName,
      },
    ];
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const distributorDetails = this.entity();
      if (distributorDetails && this.emailProvidersLoaded()) {
        this.updateFormFields();
      }
    });
  }

  ngOnInit() {
    this.fetchEmailProviders();
  }

  private fetchEmailProviders() {
    const client = this.entity();
    if (!isDefined(client) || !isString(client.id)) {
      console.warn('Invalid client data');
      return;
    }

    const filters = { state: { value: 'active', operator: '=' } };
    const rqlFilter = this.utilityService.constructRqlFilter(filters);

    this.entitiesService
      .listEmailProviders(client.id, 0, DEFAULT_LIST_SIZE, 'name', rqlFilter)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((emailProviders) => {
        this.emailProviders = [
          ...this.emailProviders,
          ...emailProviders.items.map((emailProvider) => ({
            label: isDefined(emailProvider.name)
              ? emailProvider.name
              : 'Unknown',
            value: emailProvider.id,
          })),
        ];
        this.emailProvidersLoaded.set(true);
      });
  }

  protected override updateFormFields(): void {
    this.formFields = [
      createDropdownField(
        'emailProvider',
        'Email Provider',
        this.emailProviders,
        this.entity()?.emailProvider?.id,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'emailProvider',
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const client = this.entity();
    if (isNullOrUndefined(client)) {
      return;
    }

    this.isSubmitting.set(true);
    this.accountsService
      .updateClient(client.id, formData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          this.isFormEditable.set(false);
          this.isSubmitting.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'client',
            operation: 'update',
            entityId: client.id,
            data: response,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
          this.isSubmitting.set(false);
        },
      });
  }
}
