import {
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { Validators } from '@angular/forms';
import { CommonModule } from '@angular/common';
import { catchError, of } from 'rxjs';

import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import {
  AccountsService,
  VendorCreateRequest,
  VendorResponse,
} from '../../../../../../api';
import { DEFAULT_SYSTEM_ID } from '../../../../../../core/models';
import {
  createAutocompleteField,
  createDropdownField,
  createTextField,
} from '../../../../../../shared/models/form-field.model';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { isDefined, isNullOrUndefined } from '../../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../../base';

@Component({
  selector: 'app-vendor-details',
  imports: [GridComponent, DynamicFormComponent, CommonModule],
  templateUrl: './vendor-details.component.html',
  styleUrl: './vendor-details.component.scss',
})
export class VendorDetailsComponent
  extends EntitySectionBaseComponent<VendorResponse | VendorCreateRequest>
  implements OnInit
{
  ownerId = input<string | null>(null);
  private readonly accountsService = inject(AccountsService);
  protected readonly companyGroupsLoaded = signal<boolean>(false);
  companyGroups: { label: string; value: string }[] = [];
  readonly vendorDetails = computed(() => {
    const vendorDetails = this.entity();
    if (isNullOrUndefined(vendorDetails)) return [];

    return [
      { key: 'Name', value: vendorDetails.name },
      { key: 'Website', value: vendorDetails.website },
      {
        key: 'Group',
        value:
          isDefined(vendorDetails.group) &&
          vendorDetails.group !== DEFAULT_SYSTEM_ID
            ? vendorDetails.group
            : 'None',
      },
      {
        key: 'Tags',
        value:
          (vendorDetails.tags ?? []).length > 0
            ? vendorDetails.tags?.toString()
            : 'None',
      },
    ];
  });

  constructor() {
    super();
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];
    effect(() => {
      const clientDetails = this.entity();
      if (clientDetails && this.companyGroupsLoaded() && !this.createMode()) {
        this.updateFormFields();
      }
    });
  }

  ngOnInit(): void {
    this.loadCompanyGroups();
    this.updateFormFields();
  }

  protected override updateFormFields(): void {
    this.formFields = [
      createTextField('name', 'Name', this.entity()?.name, {
        name: 'name',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Name is required',
          },
        ],
      }),
      createTextField('website', 'Website', this.entity()?.website, {
        name: 'website',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Website is required',
          },
        ],
      }),
      createDropdownField(
        'group',
        'Group',
        this.companyGroups,
        this.entity()?.group,
        {
          name: 'group',
        },
      ),

      createAutocompleteField(
        'tags',
        'Tags',
        this.entity()?.tags,
        [],
        () => {},
        {
          name: 'tags',
          props: { multiple: true, typeahead: false },
        },
      ),
    ];
  }

  private loadCompanyGroups(): void {
    const vendorDetails = this.entity();

    if (isNullOrUndefined(vendorDetails?.id)) {
      // No vendor ID available, set empty groups
      this.companyGroups = [];
      this.companyGroupsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    this.accountsService
      .listCompanyGroups(vendorDetails.id)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return of({ items: [] });
        }),
      )
      .subscribe((data) => {
        this.companyGroups = data.items
          .map((item) => ({
            label: item.name ?? '',
            value: item.id ?? '',
          }))
          .sort((a, b) => a.label.localeCompare(b.label));
        this.companyGroupsLoaded.set(true);
        this.updateFormFields();
      });
  }

  protected override submitChanges(vendorDetails: Record<string, string>) {
    const vendor = this.entity();
    if (isNullOrUndefined(vendor)) {
      throw new Error('Vendor not found');
    }

    return this.accountsService
      .updateVendorDetails(vendor.id, vendorDetails)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          this.isFormEditable.set(false);
          this.isSubmitting.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'vendor',
            operation: 'update',
            entityId: vendor.id,
            data: response,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
          this.isSubmitting.set(false);
        },
      });
  }
}
