import { Component, computed, effect, inject, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { CommonModule } from '@angular/common';

import {
  ClientResponse,
  AccountsService,
  EntitiesService,
} from '../../../../../../api';
import { createDropdownField } from '../../../../../../shared/models/form-field.model';
import { AdminStateService } from '../../../../services/admin-state.service';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { UnitFormatterService } from '../../../../../../shared/services/unit-formatter.service';
import { isNullOrUndefined } from '../../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../../base';

@Component({
  selector: 'app-client-measurement-units',
  imports: [GridComponent, DynamicFormComponent, CommonModule],
  templateUrl: './client-measurement-units.component.html',
  styleUrl: './client-measurement-units.component.scss',
})
export class ClientMeasurementUnitsComponent extends EntitySectionBaseComponent<ClientResponse> {
  private readonly accountsService = inject(AccountsService);
  private readonly entitiesService = inject(EntitiesService);
  private readonly adminTreeState = inject(AdminStateService);
  private readonly unitFormatter = inject(UnitFormatterService);
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<
    string,
    {
      value: string;
      label: string;
    }[]
  > = {};
  readonly clientDetails = computed(() => {
    const clientDetails = this.entity()?.measurementUnits;
    if (!clientDetails) return [];

    return [
      {
        key: 'Date',
        value:
          this.unitFormatter.formatMeasurementUnit(
            clientDetails.dateUnit,
            'dateUnit',
          ) ?? 'None',
      },
      {
        key: 'Time',
        value:
          this.unitFormatter.formatMeasurementUnit(
            clientDetails.timeUnit,
            'timeUnit',
          ) ?? 'None',
      },
      {
        key: 'Distance',
        value:
          this.unitFormatter.formatMeasurementUnit(
            clientDetails.distanceUnit,
            'distanceUnit',
          ) ?? 'None',
      },
      {
        key: 'Altitude',
        value:
          this.unitFormatter.formatMeasurementUnit(
            clientDetails.altitudeUnit,
            'altitudeUnit',
          ) ?? 'None',
      },
      {
        key: 'Speed',
        value:
          this.unitFormatter.formatMeasurementUnit(
            clientDetails.speedUnit,
            'speedUnit',
          ) ?? 'None',
      },
      {
        key: 'Volume',
        value:
          this.unitFormatter.formatMeasurementUnit(
            clientDetails.volumeUnit,
            'volumeUnit',
          ) ?? 'None',
      },
      {
        key: 'Weight',
        value:
          this.unitFormatter.formatMeasurementUnit(
            clientDetails.weightUnit,
            'weightUnit',
          ) ?? 'None',
      },
      {
        key: 'Area',
        value:
          this.unitFormatter.formatMeasurementUnit(
            clientDetails.areaUnit,
            'areaUnit',
          ) ?? 'None',
      },
      {
        key: 'Temperature',
        value:
          this.unitFormatter.formatMeasurementUnit(
            clientDetails.temperatureUnit,
            'temperatureUnit',
          ) ?? 'None',
      },
    ];
  });

  readonly distributorDetails = computed(() =>
    this.adminTreeState.vendorDistributor(),
  );

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const clientDetails = this.entity();
      if (clientDetails) {
        this.loadSelectOptions();
      }
    });
  }

  protected override updateFormFields(): void {
    this.formFields = [
      createDropdownField(
        'dateUnit',
        'Date',
        this.selectOptions?.['dateUnit'] ?? [],
        this.entity()?.measurementUnits?.dateUnit,
        {
          name: 'dateUnit',
          validations: [],
        },
      ),
      createDropdownField(
        'timeUnit',
        'Time',
        this.selectOptions?.['timeUnit'] ?? [],
        this.entity()?.measurementUnits?.timeUnit,
        {
          name: 'timeUnit',
          validations: [],
        },
      ),
      createDropdownField(
        'distanceUnit',
        'Distance',
        this.selectOptions?.['distanceUnit'] ?? [],
        this.entity()?.measurementUnits?.distanceUnit,
        {
          name: 'distanceUnit',
          validations: [],
        },
      ),
      createDropdownField(
        'altitudeUnit',
        'Altitude',
        this.selectOptions?.['altitudeUnit'] ?? [],
        this.entity()?.measurementUnits?.altitudeUnit,
        {
          name: 'altitudeUnit',
          validations: [],
        },
      ),
      createDropdownField(
        'speedUnit',
        'Speed',
        this.selectOptions?.['speedUnit'] ?? [],
        this.entity()?.measurementUnits?.speedUnit,
        {
          name: 'speedUnit',
          validations: [],
        },
      ),
      createDropdownField(
        'volumeUnit',
        'Volume',
        this.selectOptions?.['volumeUnit'] ?? [],
        this.entity()?.measurementUnits?.volumeUnit,
        {
          name: 'volumeUnit',
          validations: [],
        },
      ),
      createDropdownField(
        'weightUnit',
        'Weight',
        this.selectOptions?.['weightUnit'] ?? [],
        this.entity()?.measurementUnits?.weightUnit,
        {
          name: 'weightUnit',
          validations: [],
        },
      ),
      createDropdownField(
        'areaUnit',
        'Area',
        this.selectOptions?.['areaUnit'] ?? [],
        this.entity()?.measurementUnits?.areaUnit,
        {
          name: 'areaUnit',
          validations: [],
        },
      ),
      createDropdownField(
        'temperatureUnit',
        'Temperature',
        this.selectOptions?.['temperatureUnit'] ?? [],
        this.entity()?.measurementUnits?.temperatureUnit,
        {
          name: 'temperatureUnit',
          validations: [],
        },
      ),
    ];
  }

  private loadSelectOptions(): void {
    const clientDetails = this.entity();

    if (isNullOrUndefined(clientDetails?.id)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    this.entitiesService
      .getLookups('measurementUnits')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((result) => {
        // Transform the string arrays into arrays of objects with value and label
        const transformedOptions: Record<
          string,
          { value: string; label: string }[]
        > = {};

        // For each key in the result object
        Object.entries(result).forEach(([key, values]) => {
          // Transform each array of strings into an array of objects
          transformedOptions[key] = (values as string[]).map((value) => ({
            value,
            label: this.unitFormatter.formatMeasurementUnit(value, key),
          }));
        });

        this.selectOptions = transformedOptions;
        this.selectOptionsLoaded.set(true);
        this.updateFormFields();
      });
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const client = this.entity();
    if (isNullOrUndefined(client)) {
      return;
    }

    this.isSubmitting.set(true);
    this.accountsService
      .updateClient(client.id, { measurementUnits: formData })
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          this.isFormEditable.set(false);
          this.isSubmitting.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'client',
            operation: 'update',
            entityId: client.id,
            data: response,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
          this.isSubmitting.set(false);
        },
      });
  }
}
