import { Component, computed, inject, signal, effect } from '@angular/core';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormGroup } from '@angular/forms';
import { catchError, combineLatest, of, Observable } from 'rxjs';

import {
  AccountsService,
  DeviceTypeListItem,
  DistributorResponse,
  ClientResponse,
  EntitiesService,
  EmailProviderListItem,
} from '../../../../../../api';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import { BaseEntity, GridColumn } from '../../../../../../shared/models';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import {
  createDropdownField,
  createMultiselectField,
  FormAction,
} from '../../../../../../shared/models/form-field.model';
import { AdminStateService } from '../../../../services/admin-state.service';
import { EntitySectionBaseComponent } from '../../../base/entity-section-base';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../../shared/utils';

@Component({
  selector: 'app-client-settings',
  imports: [GridComponent, DynamicFormComponent, CommonModule],
  templateUrl: './client-settings.component.html',
  styleUrl: './client-settings.component.scss',
})
export class ClientSettingsComponent extends EntitySectionBaseComponent<ClientResponse> {
  private readonly adminTreeState = inject(AdminStateService);
  private readonly accountsService = inject(AccountsService);
  private readonly entitiesService = inject(EntitiesService);
  protected readonly errorMessage = signal<string | null>(null);
  selectOptions = signal<Record<string, { label: string; value: string }[]>>(
    {},
  );
  protected readonly selectOptionsLoaded = computed(
    () => Object.keys(this.selectOptions()).length > 0,
  );

  readonly clientDetails = computed(() => {
    const clientDetails = this.entity();
    if (isNullOrUndefined(clientDetails)) return [];

    return [
      {
        key: 'Map Set',
        value: clientDetails.mapSet?.name ?? 'None',
      },
      {
        key: 'Device Types',
        value: isEmpty(clientDetails.availableDeviceTypes)
          ? 'None'
          : clientDetails.availableDeviceTypes
              ?.map((deviceType) => deviceType.name)
              .join(', '),
      },
    ];
  });

  override readonly columns: GridColumn[] = [
    { field: 'key', header: '', transform: 'uppercase' },
    { field: 'value', header: '' },
  ];

  readonly distributorDetails = computed(() =>
    this.adminTreeState.vendorDistributor(),
  );

  override actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => this.isFormEditable.set(false),
      severity: 'secondary',
    },
    {
      label: 'Save',
      action: (formData: FormGroup) => {
        this.onSubmit(formData);
      },
      severity: 'primary',
      disabled: (form?: FormGroup) =>
        !isDefined(form) || form.pristine || this.isSubmitting(),
    },
  ];

  constructor() {
    super();
    effect(() => {
      const entityDetails = this.entity();
      if (entityDetails) {
        const distributorDetails = this.getDistributorDetails();
        this.loadSelectOptions(distributorDetails);
      }
    });

    effect(() => {
      this.selectOptions();
      if (this.isFormEditable()) {
        this.updateFormFields();
      }
    });
  }

  protected override updateFormFields(): void {
    this.formFields = [
      createDropdownField(
        'mapSet',
        'Map Set',
        this.selectOptions()['mapSets'] ?? [],
        this.entity()?.mapSet?.id,
        {
          name: 'mapSet',
          validations: [],
        },
      ),
      createMultiselectField(
        'availableDeviceTypes',
        'Device Types',
        this.entity()?.availableDeviceTypes?.map((dt) => dt.id) ?? [],
        this.selectOptions()['deviceTypes'] ?? [],
        {
          name: 'availableDeviceTypes',
          validations: [],
        },
      ),
    ];
  }

  protected loadSelectOptions(distributor: DistributorResponse | null): void {
    const clientDetails = this.entity();

    if (isNullOrUndefined(clientDetails?.id) || !clientDetails.owner?.id) {
      this.selectOptions.set({});
      return;
    }

    combineLatest([
      this.entitiesService.listDeviceTypes(clientDetails.owner.id),
      this.entitiesService.listEmailProviders(clientDetails.owner.id),
      this.entitiesService.listMapSets(
        clientDetails.owner.id,
        0,
        100,
        'name',
        'state!=deleted',
      ),
    ])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return of([
            { items: [] } as { items: DeviceTypeListItem[] },
            { items: [] },
            { items: [] },
          ]);
        }),
      )
      .subscribe(([deviceTypes, emailProviders, mapSets]) => {
        const deviceTypesFiltered = deviceTypes.items.filter(
          (item: DeviceTypeListItem) =>
            item.state === DeviceTypeListItem.StateEnum.Active,
        );

        this.selectOptions.set({
          deviceTypes: this.createUniqueOptions(deviceTypesFiltered),
          emailProviders: this.createUniqueOptions(
            emailProviders.items as EmailProviderListItem[],
            distributor?.availableEmailProviders ?? [],
          ),
          mapSets: this.createUniqueOptions(
            mapSets.items,
            distributor?.availableMapSets ?? [],
          ),
        });
      });
  }

  protected getDistributorDetails(): DistributorResponse | null {
    return this.adminTreeState.vendorDistributor();
  }

  protected override submitChanges(
    settings: Record<string, string>,
  ): Observable<ClientResponse> {
    const client = this.entity();
    if (!client) {
      throw new Error('Client is required');
    }
    return this.accountsService.updateClient(client.id, settings);
  }

  protected createUniqueOptions<
    T extends { id: string; name?: string | null },
    U extends { id: string; name?: string | null },
  >(items: T[], additionalItems: U[] = []): { label: string; value: string }[] {
    const uniqueMap = new Map<string, { id: string; name?: string | null }>();

    items.forEach((item) => {
      if (isDefined(item) && item.id) {
        uniqueMap.set(item.id, item);
      }
    });

    additionalItems.forEach((item) => {
      if (isDefined(item) && item.id) {
        uniqueMap.set(item.id, item);
      }
    });

    return Array.from(uniqueMap.values())
      .map((item) => ({
        label: item.name ?? '',
        value: item.id,
      }))
      .sort((a, b) => a.label.localeCompare(b.label));
  }

  override onSubmit(formGroup: FormGroup): void {
    if (!this.entity()) return;

    this.isSubmitting.set(true);
    this.errorMessage.set(null);

    const dirtyValues = this.getDirtyValues(formGroup);

    if (isDefined(dirtyValues['availableDeviceTypes'])) {
      const deviceTypeIds = dirtyValues['availableDeviceTypes'] as string[];
      const mappedDeviceTypes = deviceTypeIds.map((id) => {
        const selected = this.selectOptions()['deviceTypes']?.find(
          (opt) => opt.value === id,
        );
        return {
          id: id,
          name: selected ? selected.label : null,
        };
      });

      // Filter out device types that couldn't be mapped (have null names)
      const validDeviceTypes = mappedDeviceTypes.filter(
        (dt) => dt.name !== null,
      );

      // If all device types are valid, use the mapped array; otherwise use the valid ones
      dirtyValues['availableDeviceTypes'] =
        validDeviceTypes.length === mappedDeviceTypes.length
          ? mappedDeviceTypes
          : validDeviceTypes;
    }

    if (isDefined(dirtyValues['mapSet'])) {
      const mapSetOption = this.selectOptions()['mapSets']?.find(
        (opt) => opt.value === dirtyValues['mapSet'],
      );
      if (mapSetOption) {
        dirtyValues['mapSet'] = {
          id: mapSetOption.value,
          name: mapSetOption.label,
        };
      } else {
        // Fallback: if no matching option is found, remove the mapSet field entirely
        // This prevents sending an invalid mapSet value to the API
        delete dirtyValues['mapSet'];
      }
    }

    if (Object.keys(dirtyValues).length === 0) {
      this.isFormEditable.set(false);
      this.isSubmitting.set(false);
      return;
    }

    this.submitChanges(dirtyValues as Record<string, string>)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          this.isFormEditable.set(false);
          this.isSubmitting.set(false);
          this.entityChange.emit(response);
          this.broadcastService.broadcast('entity-updated', {
            entityType: this.entityType(),
            operation: 'update',
            entityId: (response as BaseEntity).id,
            data: response,
          });
        },
        error: () => {
          this.errorMessage.set('Failed to update settings');
          this.isSubmitting.set(false);
        },
      });
  }
}
