import { Component, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormGroup } from '@angular/forms';
import { catchError, combineLatest, of } from 'rxjs';

import {
  DeviceTypeListItem,
  DistributorResponse,
  VendorResponse,
} from '../../../../../../api';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import { GridColumn } from '../../../../../../shared/models';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import {
  createDropdownField,
  createMultiselectField,
  FormAction,
} from '../../../../../../shared/models/form-field.model';
import { AdminStateService } from '../../../../services/admin-state.service';
import { EntitySettingsBase } from '../../../base';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../../shared/utils';

@Component({
  selector: 'app-vendor-settings',
  imports: [GridComponent, DynamicFormComponent, CommonModule],
  templateUrl: './vendor-settings.component.html',
  styleUrl: './vendor-settings.component.scss',
})
export class VendorSettingsComponent extends EntitySettingsBase<VendorResponse> {
  private readonly adminTreeState = inject(AdminStateService);
  readonly vendorDetails = computed(() => {
    const vendorDetails = this.entity();
    if (isNullOrUndefined(vendorDetails)) return [];

    return [
      {
        key: 'Available Email providers',
        value: isEmpty(vendorDetails.availableEmailProviders)
          ? 'None'
          : vendorDetails.availableEmailProviders
              ?.map((provider) => provider.name)
              .join(', '),
      },
      {
        key: 'Available Map Sets',
        value: isEmpty(vendorDetails.availableMapSets)
          ? 'None'
          : vendorDetails.availableMapSets
              ?.map((mapSet) => mapSet.name)
              .join(', '),
      },
      {
        key: 'Default Map Set',
        value: vendorDetails.defaultMapSet?.name ?? 'None',
      },
      {
        key: 'Device Types',
        value: isEmpty(vendorDetails.availableDeviceTypes)
          ? 'None'
          : vendorDetails.availableDeviceTypes
              ?.map((deviceType) => deviceType.name)
              .join(', '),
      },
    ];
  });

  readonly columns: GridColumn[] = [
    { field: 'key', header: '', transform: 'uppercase' },
    { field: 'value', header: '' },
  ];

  readonly distributorDetails = computed(() =>
    this.adminTreeState.vendorDistributor(),
  );

  actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => this.isFormEditable.set(false),
      severity: 'secondary',
    },
    {
      label: 'Save',
      action: (formData: FormGroup) => {
        this.onSubmit(formData);
      },
      severity: 'primary',
      disabled: (form?: FormGroup) => !isDefined(form) || form.pristine,
    },
  ];

  protected override updateFormFields(): void {
    this.formFields = [
      createMultiselectField(
        'availableEmailProviders',
        'Email Providers',
        this.entity()?.availableEmailProviders?.map(
          (provider) => provider.id,
        ) ?? [],
        this.selectOptions?.['emailProviders'] ?? [],
        {
          name: 'availableEmailProviders',
          validations: [],
        },
      ),
      createMultiselectField(
        'availableMapSets',
        'Map Sets',
        this.entity()?.availableMapSets?.map((mapSet) => mapSet.id) ?? [],
        this.selectOptions?.['mapSets'] ?? [],
        {
          name: 'availableMapSets',
          validations: [],
        },
      ),
      createDropdownField(
        'defaultMapSet',
        'Default Map Set',
        this.selectOptions?.['mapSets'] ?? [],
        this.entity()?.defaultMapSet?.id,
        {
          name: 'defaultMapSet',
          validations: [],
        },
      ),
      createMultiselectField(
        'availableDeviceTypes',
        'Device Types',
        this.entity()?.availableDeviceTypes?.map((dt) => dt.id) ?? [],
        this.selectOptions?.['deviceTypes'] ?? [],
        {
          name: 'availableDeviceTypes',
          validations: [],
        },
      ),
    ];
  }

  protected override loadSelectOptions(
    distributor: DistributorResponse | null,
  ): void {
    const vendorDetails = this.entity();

    if (isNullOrUndefined(vendorDetails?.id)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    combineLatest([
      this.entitiesService.listDeviceTypes(vendorDetails.owner.id),
      this.entitiesService.listEmailProviders(vendorDetails.owner.id),
      this.entitiesService.listMapSets(
        vendorDetails.owner.id,
        0,
        100,
        'name',
        'state!=deleted',
      ),
    ])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return of([{ items: [] }, { items: [] }, { items: [] }]);
        }),
      )
      .subscribe(([deviceTypes, emailProviders, mapSets]) => {
        // Device types - filter first then create options
        const deviceTypesFiltered = deviceTypes.items.filter(
          (item) => item.state === DeviceTypeListItem.StateEnum.Active,
        );

        this.selectOptions = {
          deviceTypes: this.createUniqueOptions(deviceTypesFiltered),
          emailProviders: this.createUniqueOptions(
            emailProviders.items,
            distributor?.availableEmailProviders ?? [],
          ),
          mapSets: this.createUniqueOptions(
            mapSets.items,
            distributor?.availableMapSets ?? [],
          ),
        };

        this.selectOptionsLoaded.set(true);
        this.updateFormFields();
      });
  }

  protected override getDistributorDetails(): DistributorResponse | null {
    return this.adminTreeState.vendorDistributor();
  }

  protected override submitChanges(settings: Record<string, string>) {
    const vendor = this.entity();
    if (!vendor) {
      throw new Error('Vendor is required');
    }
    return this.accountsService.updateVendorDetails(vendor.id, settings);
  }
}
