import {
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { Validators } from '@angular/forms';
import { CommonModule } from '@angular/common';
import { catchError, of } from 'rxjs';

import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import {
  AccountsService,
  ClientCreateRequest,
  ClientResponse,
} from '../../../../../../api';
import { DEFAULT_SYSTEM_ID } from '../../../../../../core/models';
import {
  createAutocompleteField,
  createDropdownField,
  createTextField,
} from '../../../../../../shared/models/form-field.model';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { isDefined, isNullOrUndefined } from '../../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../../base';
import { HttpClient } from '@angular/common/http';
import { RequestCacheService } from '../../../../../../shared/services/request-cache.service';
import { BaseEntity } from '../../../../../../shared/models';

@Component({
  selector: 'app-client-details',
  imports: [GridComponent, DynamicFormComponent, CommonModule],
  templateUrl: './client-details.component.html',
  styleUrl: './client-details.component.scss',
})
export class ClientDetailsComponent
  extends EntitySectionBaseComponent<ClientResponse | ClientCreateRequest>
  implements OnInit
{
  ownerId = input<string | null>(null);
  private readonly http = inject(HttpClient);
  protected readonly companyGroupsLoaded = signal<boolean>(false);
  companyGroups: { label: string; value: string }[] = [];
  readonly clientDetails = computed(() => {
    const clientDetails = this.entity();
    const groupsLoaded = this.companyGroupsLoaded();
    if (!clientDetails) return [];
    let groupName = 'None';

    if (
      isDefined(clientDetails.group) &&
      clientDetails.group !== DEFAULT_SYSTEM_ID
    ) {
      if (groupsLoaded) {
        groupName =
          this.companyGroups.find(
            (group) => group.value === clientDetails.group,
          )?.label ?? 'Unknown';
      } else {
        groupName = 'Loading...';
      }
    }

    return [
      { key: 'Name', value: clientDetails.name },
      { key: 'Website', value: clientDetails.website },
      { key: 'Group', value: groupName },
      {
        key: 'Tags',
        value:
          (clientDetails.tags ?? []).length > 0
            ? clientDetails.tags?.toString()
            : 'None',
      },
      { key: 'Pin', value: clientDetails.pin ?? 'None' },
    ];
  });
  private readonly accountsService = inject(AccountsService);
  timezones: { label: string; value: string }[] = [];
  private readonly cacheService = inject(RequestCacheService);
  cacheTTL = 300000; // 5 minutes

  constructor() {
    super();
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const clientDetails = this.entity();
      if (clientDetails && this.companyGroupsLoaded() && !this.createMode()) {
        this.updateFormFields();
      }
    });
  }

  ngOnInit(): void {
    this.loadCompanyGroups();
    this.loadTimezones();
    this.updateFormFields();
  }

  private loadTimezones(): void {
    this.http
      .get<{ id: string; name: string }[]>('/assets/docs/timezones.json')
      .subscribe((data) => {
        this.timezones = data
          .map((tz) => ({ label: tz.id, value: tz.id }))
          .sort((a, b) => a.label.localeCompare(b.label));
      });
  }

  protected override updateFormFields(): void {
    this.formFields = [
      createTextField('name', 'Name', this.entity()?.name, {
        name: 'name',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Name is required',
          },
        ],
      }),
      createTextField('website', 'Website', this.entity()?.website, {
        name: 'website',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Website is required',
          },
        ],
      }),
      createDropdownField(
        'group',
        'Group',
        this.companyGroups,
        this.entity()?.group,
        {
          name: 'group',
        },
      ),
      createDropdownField(
        'timeZoneId',
        'Timezone',
        this.timezones,
        this.entity()?.timeZoneId ?? null,
        {
          name: 'timeZoneId',
          placeholder: 'Select timezone',
          props: { appendTo: 'body' },
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Timezone required',
            },
          ],
        },
      ),
      createAutocompleteField(
        'tags',
        'Tags',
        this.entity()?.tags,
        [],
        () => {},
        {
          name: 'tags',
          props: { multiple: true, typeahead: false },
        },
      ),
      ...(!this.createMode()
        ? [
            createTextField('pin', 'Pin', this.entity()?.pin, {
              name: 'pin',
              disabled: true,
            }),
          ]
        : []),
    ];
  }

  private loadCompanyGroups(): void {
    const clientDetails = this.entity();
    const ownerId = clientDetails?.owner?.id ?? this.ownerId();

    if (isNullOrUndefined(ownerId)) {
      // No client ID available, set empty groups
      this.companyGroups = [];
      this.companyGroupsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    this.cacheService
      .getOrFetch(
        `company-groups-${ownerId}`,
        () => this.accountsService.listCompanyGroups(ownerId),
        this.cacheTTL,
      )
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return of({ items: [] });
        }),
      )
      .subscribe((data) => {
        this.companyGroups = [
          { value: DEFAULT_SYSTEM_ID, label: 'None' },
          ...data.items
            .map((item) => ({
              label: item.name ?? '',
              value: item.id ?? '',
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        ];
        this.companyGroupsLoaded.set(true);
        this.updateFormFields();
      });
  }

  protected override submitChanges(clientDetails: Record<string, string>) {
    const client = this.entity();
    if (isNullOrUndefined(client)) {
      throw new Error('Client not found');
    }
    this.accountsService.updateClient(client.id, clientDetails).subscribe({
      next: (response) => {
        this.isFormEditable.set(false);
        this.isSubmitting.set(false);
        this.entityChange.emit(response);
        this.broadcastService.broadcast('entity-updated', {
          entityType: 'client',
          operation: 'update',
          entityId: (response as BaseEntity).id,
          data: response,
        });
      },
      error: () => {
        this.isSubmitting.set(false);
      },
    });
  }
}
