import { CommonModule } from '@angular/common';
import { HttpClient } from '@angular/common/http';
import { Component, computed, effect, inject, signal } from '@angular/core';
import { FormGroup, Validators } from '@angular/forms';
import { Observable, take } from 'rxjs';

import { AccountsService, ClientResponse } from '../../../../../../api';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import {
  createDropdownField,
  createTextField,
  FormAction,
} from '../../../../../../shared/models/form-field.model';
import { RequestCacheService } from '../../../../../../shared/services/request-cache.service';
import {
  isDefined,
  isNullOrUndefined,
  isString,
} from '../../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../../base/entity-section-base';

@Component({
  selector: 'app-client-address',
  imports: [DynamicFormComponent, GridComponent, CommonModule],
  templateUrl: './client-address.component.html',
  styleUrl: './client-address.component.scss',
})
export class ClientAddressComponent extends EntitySectionBaseComponent<ClientResponse> {
  private readonly accountsService = inject(AccountsService);
  private readonly cacheService = inject(RequestCacheService);
  private readonly http = inject(HttpClient);

  readonly countries = signal<{ label: string; value: string }[]>([]);
  readonly countriesLoaded = computed(() => this.countries().length > 0);
  override readonly isFormEditable = signal(false);

  readonly address = computed(() => {
    const clientDetails = this.entity();

    if (isNullOrUndefined(clientDetails) || !this.countriesLoaded()) {
      return [];
    }
    const address = clientDetails.address;
    return [
      {
        key: 'Address',
        value: isString(address?.address) ? address.address : 'None',
      },
      {
        key: 'City',
        value: isString(address?.city) ? address.city : 'None',
      },
      {
        key: 'State',
        value: isString(address?.state) ? address.state : 'None',
      },
      {
        key: 'Code',
        value: isString(address?.code) ? address.code : 'None',
      },
      {
        key: 'Country',
        value: this.findCountryLabel(address?.country ?? undefined),
      },
    ];
  });

  constructor() {
    super();
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];
    this.loadCountries();
    effect(() => {
      if (this.isFormEditable()) {
        this.updateFormFields();
      }
    });
  }

  override actions: FormAction[] = [
    {
      label: 'Cancel',
      action: (): void => this.isFormEditable.set(false),
      severity: 'secondary',
    },
    {
      label: 'Save',
      action: (formData: FormGroup): void => {
        this.onSubmit(formData);
      },
      severity: 'primary',
      disabled: (form?: FormGroup): boolean =>
        !isDefined(form) || form.pristine,
    },
  ];

  protected override updateFormFields(): void {
    const client = this.entity();
    this.formFields = [
      createTextField('address', 'Address', client?.address?.address, {
        name: 'address',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Address is required',
          },
        ],
      }),

      createTextField('city', 'City', client?.address?.city, {
        name: 'city',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'City is required',
          },
        ],
      }),

      createTextField('state', 'State', client?.address?.state, {
        name: 'state',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'State is required',
          },
        ],
      }),

      createTextField('code', 'Code', client?.address?.code, {
        name: 'code',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Code is required',
          },
        ],
      }),

      createDropdownField(
        'country',
        'Country',
        this.countries(),
        client?.address?.country,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          placeholder: 'Select country',
          name: 'country',
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];
  }

  protected override submitChanges(addressData: {
    address: Record<string, string>;
  }): Observable<ClientResponse> {
    const client = this.entity();
    if (!client) {
      throw new Error('Client is required');
    }
    return this.accountsService.updateClientDetails(client.id, {
      address: addressData.address,
    });
  }

  private loadCountries(): void {
    this.cacheService
      .getOrFetch('countries', () =>
        this.http.get<Record<string, string>>('assets/docs/countries.json'),
      )
      .pipe(take(1))
      .subscribe((countries) => {
        if (isDefined(countries) && [countries].length > 0) {
          this.countries.set(
            Object.entries(countries).map(([code, name]) => ({
              label: name,
              value: code,
            })),
          );
        }
      });
  }

  protected findCountryLabel(countryCode: string | undefined): string {
    if (isNullOrUndefined(countryCode) || !this.countriesLoaded())
      return 'None';
    const country = this.countries().find((c) => c.value === countryCode);
    return country?.label ?? 'None';
  }

  protected override onSubmit(formGroup: FormGroup): void {
    if (formGroup.invalid) {
      return;
    }
    this.submitChanges({ address: formGroup.value }).subscribe({
      next: (response) => {
        this.isFormEditable.set(false);
        this.entityChange.emit(response);
      },
      error: (error) => {
        console.error('Failed to save address', error);
      },
    });
  }
}
