import {
  Component,
  computed,
  effect,
  inject,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { finalize } from 'rxjs';

import {
  createDropdownField,
  createTextAreaField,
} from '../../../../../../shared/models/form-field.model';
import {
  VendorResponse,
  ThemeListItem,
  AccountsService,
  ThemesService,
} from '../../../../../../api';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import { ApiUrlService } from '../../../../../../core/services/api-url.service';
import { UtilsService } from '../../../../../../shared/services/utils.service';
import { LogoTemplateContext } from '../../../../models/templates.interface';
import { ImageEditorComponent } from '../../../../../../shared/components/image-editor/image-editor.component';
import { isDefined } from '../../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../../base';

@Component({
  selector: 'app-customize-vendor',
  imports: [
    CommonModule,
    DynamicFormComponent,
    GridComponent,
    ImageEditorComponent,
  ],
  templateUrl: './customize-vendor.component.html',
  styleUrl: './customize-vendor.component.scss',
})
export class CustomizeVendorComponent extends EntitySectionBaseComponent<VendorResponse> {
  @ViewChild('customTemplate', { static: true }) logoTemplate:
    | TemplateRef<LogoTemplateContext>
    | undefined;

  private readonly accountsService = inject(AccountsService);
  private readonly themesService = inject(ThemesService);
  private readonly utilsService = inject(UtilsService);

  private readonly apiUrlService = inject(ApiUrlService);

  readonly vendorDetails = computed(() => {
    const details = this.entity();

    if (!details) return [];

    return [
      {
        key: 'Logo',
        value: '',
        imageUrl: `${this.apiUrlService.getCurrentApiUrl()}/accounts/vendors/${details.id}/logo?size=large`,
        imageCaption:
          'The image will be resampled to 800 x 333 pixels and will be used on reports.',
      },
      {
        key: 'Web Logo',
        value: '',
        imageUrl: `${this.apiUrlService.getCurrentApiUrl()}/accounts/vendors/${details.id}/logo?size=small`,
        imageCaption:
          'The image will be resampled to 240 x 100 pixels. For better results you should pre-scale your image in a graphics program before uploading.',
      },
      {
        key: 'Domains',
        value: isDefined(details.domains?.length)
          ? details.domains.join(', ')
          : 'None',
      },
      {
        key: 'Language',
        value:
          this.languages.find((l) => l.id === details.language)?.name ?? 'None',
      },
      {
        key: 'Theme',
        value: details?.theme?.name ?? 'None',
      },
      {
        key: 'Login Message',
        value:
          isDefined(details?.messages?.login) && details?.messages?.login !== ''
            ? details?.messages?.login
            : 'None',
      },
    ];
  });
  readonly languages = this.utilsService.getLanguages();
  themes: ThemeListItem[] = [];
  isImageEditorVisible = false;
  file: string | undefined;

  constructor() {
    super();

    effect(() => {
      const vendor = this.entity();
      if (vendor) {
        this.themesService
          .listThemes(vendor.id)
          .pipe(takeUntilDestroyed(this.destroyRef))
          .subscribe({
            next: (themes) => {
              this.themes = themes.items;
              this.updateFormFields();
            },
          });
      }
    });

    effect(() => {
      if (this.logoTemplate) {
        this.columnsSignal.set([
          { field: 'key', header: '', transform: 'uppercase' },
          { field: 'value', header: '', cellTemplate: this.logoTemplate },
        ]);
      }
    });
  }

  protected override updateFormFields(): void {
    this.formFields = [
      createTextAreaField(
        'domains',
        'Domains',
        this.entity()?.domains?.join(', '),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'domains',
        },
      ),
      createDropdownField(
        'language',
        'Language',
        this.languages.map((lang) => ({
          label: lang.name,
          value: lang.id,
        })),
        this.entity()?.language,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          placeholder: 'Select language',
          name: 'language',
          props: {
            // Using 'body' to ensure proper overlay positioning and width
            // Alternative approaches with container elements can cause positioning issues
            appendTo: 'body',
          },
        },
      ),
      createDropdownField(
        'theme',
        'Theme',
        [{ label: 'Inherited', value: 'inherited' }].concat(
          this.themes.map((theme) => ({
            label: theme.name,
            value: theme.id,
          })),
        ),
        this.entity()?.theme?.id,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          placeholder: 'Select theme',
          name: 'theme',
          props: {
            appendTo: 'body',
          },
        },
      ),
      {
        name: 'messages',
        key: 'messages',
        type: 'group',
        fields: [
          createTextAreaField(
            'login',
            'Login Message',
            this.entity()?.messages?.login,
            {
              layout: 'horizontal',
              labelWidth: '1/3',
              name: 'login',
              hint: 'Markdown syntax is supported for styling text.',
            },
          ),
        ],
      },
    ];
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const currentVendor = this.entity();
    if (!currentVendor) return;

    this.accountsService
      .updateVendorDetails(currentVendor.id, formData)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.isSubmitting.set(false)),
      )
      .subscribe({
        next: (response) => {
          this.isFormEditable.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'vendor',
            operation: 'update',
            entityId: currentVendor.id,
            data: response,
          });
        },
        error: () => this.isFormEditable.set(true),
      });
  }

  onImageEditorVisibleChange(visible: boolean, file?: string): void {
    this.isImageEditorVisible = visible;
    this.file = file;
  }

  saveFile(file: File): void {
    if (!this.entity()) return;

    this.isSubmitting.set(true);

    const formData = new FormData();
    formData.append('logo', file);
  }

  updateLogo() {
    // To be implemented when formData is added to the API
    return;
  }
}
