import { Type } from '@angular/core';
import {
  DistributorResponse,
  VendorResponse,
  ClientResponse,
} from '../../../api';
import { AdminDetailSection, EntitySection } from '../models';

// Component imports
import { CustomizeDistributorComponent } from '../components/distributors/distributor-details/customize-distributor/customize-distributor.component';
import { DistributorAddressComponent } from '../components/distributors/distributor-details/distributor-address/distributor-address.component';
import { DistributorDetailsComponent } from '../components/distributors/distributor-details/distributor-details/distributor-details.component';
import { DistributorExternalAuthenticationComponent } from '../components/distributors/distributor-details/distributor-external-authentication/distributor-external-authentication.component';
import { DistributorNotificationSettingsComponent } from '../components/distributors/distributor-details/distributor-notification-settings/distributor-notification-settings.component';
import { DistributorSettingsComponent } from '../components/distributors/distributor-details/distributor-settings/distributor-settings.component';
import { DistributorSslCertificatesComponent } from '../components/distributors/distributor-details/distributor-ssl-certificates/distributor-ssl-certificates.component';
import { CustomizeVendorComponent } from '../components/vendors/vendor-details/customize-vendor/customize-vendor.component';
import { VendorAddressComponent } from '../components/vendors/vendor-details/vendor-address/vendor-address.component';
import { VendorSettingsComponent } from '../components/vendors/vendor-details/vendor-settings/vendor-settings.component';
import { VendorNotificationSettingsComponent } from '../components/vendors/vendor-details/vendor-notification-settings/vendor-notification-settings.component';
import { VendorExternalAuthenticationComponent } from '../components/vendors/vendor-details/vendor-external-authentication/vendor-external-authentication.component';
import { VendorDetailsComponent } from '../components/vendors/vendor-details/vendor-details/vendor-details.component';
import { ClientDetailsComponent } from '../components/clients/client-details/client-details/client-details.component';
import { CustomizeClientComponent } from '../components/clients/client-details/customize-client/customize-client.component';
import { ClientAddressComponent } from '../components/clients/client-details/client-address/client-address.component';
import { ClientSettingsComponent } from '../components/clients/client-details/client-settings/client-settings.component';
import { ClientNotificationSettingsComponent } from '../components/clients/client-details/client-notification-settings/client-notification-settings.component';
import { ClientExternalAuthenticationComponent } from '../components/clients/client-details/client-external-authentication/client-external-authentication.component';
import { ClientMeasurementUnitsComponent } from '../components/clients/client-details/client-measurement-units/client-measurement-units.component';
import { FeedSectionComponent } from '../components/shared/feed-section/feed-section.component';

export class SectionConfigBuilder<T> {
  private readonly sections: AdminDetailSection[] = [];

  constructor(
    private readonly entity: T | null,
    private readonly entityType: string,
  ) {}

  /**
   * Add a section to the builder
   */
  addSection(
    id: string,
    title: string,
    component: Type<EntitySection<unknown>>,
    options?: {
      category?:
        | 'information'
        | 'settings'
        | 'statistics'
        | 'feed'
        | 'features'
        | 'custom';
      order?: number;
      visible?: boolean | ((entity: unknown) => boolean);
      readonly?: boolean;
    },
    componentInputs?: Record<string, unknown>,
  ): this {
    this.sections.push({
      id,
      title,
      component,
      componentInputs: {
        entity: this.entity,
        ...(componentInputs ?? {}),
      },
      category: options?.category ?? 'information',
      order: options?.order ?? 0,
      visible: options?.visible,
      readonly: options?.readonly,
    });
    return this;
  }

  /**
   * Build the final sections array
   */
  build(): AdminDetailSection[] {
    return this.sections;
  }

  /**
   * Create a builder for distributor sections
   */
  static forDistributor(
    entity: DistributorResponse | null,
  ): SectionConfigBuilder<DistributorResponse> {
    return new SectionConfigBuilder<DistributorResponse>(entity, 'distributor');
  }

  /**
   * Create a builder for vendor sections
   */
  static forVendor(
    entity: VendorResponse | null,
  ): SectionConfigBuilder<VendorResponse> {
    return new SectionConfigBuilder<VendorResponse>(entity, 'vendor');
  }

  /**
   * Create a builder for client sections
   */
  static forClient(
    entity: ClientResponse | null,
  ): SectionConfigBuilder<ClientResponse> {
    return new SectionConfigBuilder<ClientResponse>(entity, 'client');
  }

  /**
   * Create standard distributor information sections
   */
  static createDistributorInformationSections(
    entity: DistributorResponse | null,
  ): AdminDetailSection[] {
    return SectionConfigBuilder.forDistributor(entity)
      .addSection('details', 'Distributor Details', DistributorDetailsComponent)
      .addSection(
        'customize',
        'Customize Distributor',
        CustomizeDistributorComponent,
      )
      .addSection('address', 'Distributor Address', DistributorAddressComponent)
      .addSection(
        'ssl-certificates',
        'SSL Certificates',
        DistributorSslCertificatesComponent,
      )
      .build();
  }

  /**
   * Create standard distributor settings sections
   */
  static createDistributorSettingsSections(
    entity: DistributorResponse | null,
  ): AdminDetailSection[] {
    return SectionConfigBuilder.forDistributor(entity)
      .addSection('settings', 'Settings', DistributorSettingsComponent, {
        category: 'settings',
        order: 10,
      })
      .addSection(
        'notification-settings',
        'Notification Settings',
        DistributorNotificationSettingsComponent,
        {
          category: 'settings',
          order: 20,
        },
      )
      .addSection(
        'external-authentication',
        'External Authentication',
        DistributorExternalAuthenticationComponent,
        {
          category: 'settings',
          order: 30,
        },
      )
      .build();
  }

  /**
   * Create standard vendor information sections
   */
  static createVendorInformationSections(
    entity: VendorResponse | null,
  ): AdminDetailSection[] {
    return SectionConfigBuilder.forVendor(entity)
      .addSection('details', 'Vendor Details', VendorDetailsComponent)
      .addSection('customize', 'Customize Vendor', CustomizeVendorComponent)
      .addSection('address', 'Vendor Address', VendorAddressComponent)
      .build();
  }

  /**
   * Create standard vendor settings sections
   */
  static createVendorSettingsSections(
    entity: VendorResponse | null,
  ): AdminDetailSection[] {
    return SectionConfigBuilder.forVendor(entity)
      .addSection(
        'settings',
        'Settings',
        VendorSettingsComponent,
        {
          category: 'settings',
          order: 10,
        },
        {
          entityType: 'vendor',
        },
      )
      .addSection(
        'notification-settings',
        'Notification Settings',
        VendorNotificationSettingsComponent,
        {
          category: 'settings',
          order: 20,
        },
        {
          entityType: 'vendor',
        },
      )
      .addSection(
        'external-authentication',
        'External Authentication',
        VendorExternalAuthenticationComponent,
        {
          category: 'settings',
          order: 30,
        },
        {
          entityType: 'vendor',
        },
      )
      .build();
  }

  /**
   * Create standard client information sections
   */
  static createClientInformationSections(
    entity: ClientResponse | null,
  ): AdminDetailSection[] {
    return SectionConfigBuilder.forClient(entity)
      .addSection('details', 'Client Details', ClientDetailsComponent)
      .addSection('customize', 'Customize Client', CustomizeClientComponent)
      .addSection('address', 'Client Address', ClientAddressComponent)
      .build();
  }

  /**
   * Create standard client settings sections
   */
  static createClientSettingsSections(
    entity: ClientResponse | null,
  ): AdminDetailSection[] {
    return SectionConfigBuilder.forClient(entity)
      .addSection(
        'settings',
        'Settings',
        ClientSettingsComponent,
        {
          category: 'settings',
          order: 10,
        },
        {
          entityType: 'client',
        },
      )
      .addSection(
        'notification-settings',
        'Notification Settings',
        ClientNotificationSettingsComponent,
        {
          category: 'settings',
          order: 20,
        },
        {
          entityType: 'client',
        },
      )
      .addSection(
        'measurement-units',
        'Measurement Units',
        ClientMeasurementUnitsComponent,
        {
          category: 'settings',
          order: 30,
        },
        {
          entityType: 'client',
        },
      )
      .addSection(
        'external-authentication',
        'External Authentication',
        ClientExternalAuthenticationComponent,
        {
          category: 'settings',
          order: 40,
        },
        {
          entityType: 'client',
        },
      )
      .build();
  }

  /**
   * Create standard client changes sections
   */
  static createClientChangesSections(
    entity: ClientResponse | null,
  ): AdminDetailSection[] {
    return SectionConfigBuilder.forClient(entity)
      .addSection(
        'changes',
        'Changes',
        FeedSectionComponent,
        {
          category: 'feed',
          order: 10,
        },
        {
          entity,
        },
      )
      .build();
  }

  /**
   * Create all sections for an entity type
   */
  static createSections<
    T extends DistributorResponse | VendorResponse | ClientResponse,
  >(
    entity: T | null,
    entityType: 'distributor' | 'vendor' | 'client',
    sectionType: 'information' | 'settings' | 'statistics',
  ): AdminDetailSection[] {
    if (entityType === 'distributor') {
      if (sectionType === 'information') {
        return SectionConfigBuilder.createDistributorInformationSections(
          entity as DistributorResponse | null,
        );
      } else if (sectionType === 'settings') {
        return SectionConfigBuilder.createDistributorSettingsSections(
          entity as DistributorResponse | null,
        );
      }
    } else if (entityType === 'vendor') {
      if (sectionType === 'information') {
        return SectionConfigBuilder.createVendorInformationSections(
          entity as VendorResponse | null,
        );
      } else if (sectionType === 'settings') {
        return SectionConfigBuilder.createVendorSettingsSections(
          entity as VendorResponse | null,
        );
      }
      // Add other vendor section types
    }
    // Add client sections
    else if (entityType === 'client') {
      if (sectionType === 'information') {
        return SectionConfigBuilder.createClientInformationSections(
          entity as ClientResponse | null,
        );
      } else if (sectionType === 'settings') {
        return SectionConfigBuilder.createClientSettingsSections(
          entity as ClientResponse | null,
        );
      } else if (sectionType === 'statistics') {
        return SectionConfigBuilder.createClientChangesSections(
          entity as ClientResponse | null,
        );
      }
    }

    return [];
  }

  /**
   * Create standard distributor changes sections
   */
  static createDistributorChangesSections(
    entity: DistributorResponse | null,
  ): AdminDetailSection[] {
    return SectionConfigBuilder.forDistributor(entity)
      .addSection(
        'changes',
        'Changes',
        FeedSectionComponent,
        {
          category: 'feed',
          order: 10,
        },
        {
          entity,
        },
      )
      .build();
  }
}
