import { Component, effect, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import { ButtonModule } from 'primeng/button';
import { TooltipModule } from 'primeng/tooltip';
import { CardModule } from 'primeng/card';
import { TimelineModule } from 'primeng/timeline';
import { DividerModule } from 'primeng/divider';

import {
  ClientResponse,
  FeedsService,
  AuditEventResponse,
  AuditEventChange,
} from '../../../../../api';
import { TimeAgoPipe } from '../../../../../shared/pipes/time-ago.pipe';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { MeasurementDateTimeService } from '../../../../../shared/services/measurement-units/measurement-date-time.service';
import { AuditFeedItem } from '../../../models/audit.interface';

interface GroupedAuditFeed {
  date: string;
  formattedDate: string;
  items: AuditFeedItem[];
}

@Component({
  selector: 'app-feed-section',
  imports: [
    CommonModule,
    TimelineModule,
    ButtonModule,
    CardModule,
    TooltipModule,
    DividerModule,
    TimeAgoPipe,
  ],
  templateUrl: './feed-section.component.html',
  styleUrl: './feed-section.component.scss',
})
export class FeedSectionComponent extends EntitySectionBaseComponent<ClientResponse> {
  // Constants
  private static readonly PAGE_SIZE = 10;
  private static readonly TIMESTAMP_UPDATE_INTERVAL = 60000; // 1 minute

  private readonly feedService = inject(FeedsService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );

  readonly auditFeed = signal<AuditFeedItem[]>([]);
  readonly loading = signal<boolean>(false);
  readonly error = signal<string | null>(null);
  readonly hasMoreData = signal<boolean>(true);

  private currentSequence = 0;
  private readonly pageSize = FeedSectionComponent.PAGE_SIZE;
  readonly loadingMore = signal<boolean>(false);
  private currentEntityId = '';
  private readonly timestampIntervalId: NodeJS.Timeout;

  groupedAuditFeed = signal<GroupedAuditFeed[]>([]);
  readonly timestamp = signal(Date.now());

  constructor() {
    super();
    effect(() => {
      this.groupItemsByDate(this.auditFeed());
    });

    effect(() => {
      const entity = this.entity();
      const entityId = entity?.id; // Only load if entity exists and is different from current one
      if (isDefined(entityId) && entityId !== this.currentEntityId) {
        this.currentEntityId = entityId;
        // Clear existing data when switching entities
        this.auditFeed.set([]);
        this.hasMoreData.set(true);
        this.loadInitialData();
      }
    });

    // Update timestamp every minute to refresh "time ago" displays
    this.timestampIntervalId = setInterval(() => {
      this.timestamp.set(Date.now());
    }, FeedSectionComponent.TIMESTAMP_UPDATE_INTERVAL);

    // Clear interval on component destroy
    this.destroyRef.onDestroy(() => {
      clearInterval(this.timestampIntervalId);
    });
  }

  /**
   * Load initial audit feed data for the current entity
   */
  loadInitialData(): void {
    // Prevent duplicate calls if already loading
    if (this.loading()) {
      return;
    }

    const clientId = this.entity()?.id;

    if (isNullOrUndefined(clientId)) {
      this.error.set('Client information not available');
      return;
    }

    const companyId = this.entity()?.owner?.id;

    if (isNullOrUndefined(companyId)) {
      this.error.set('Company information not available');
      return;
    }

    // Get today's date in GMT and convert to Unix timestamp
    const today = new Date();
    today.setUTCHours(23, 59, 59, 999); // Set to end of day GMT
    this.currentSequence = Math.floor(today.getTime() / 1000);

    this.loading.set(true);
    this.error.set(null);

    this.feedService
      .getAuditFeedForEntity(
        companyId,
        clientId,
        this.currentSequence,
        'backward',
        this.pageSize,
      )
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          const items = this.transformAuditEventItems(response.items);
          // Filter out any duplicates that might already exist
          const existingIds = new Set(this.auditFeed().map((item) => item.id));
          const newItems = items.filter((item) => !existingIds.has(item.id));
          this.auditFeed.set(newItems);

          // Update sequence for next load based on the oldest item
          if (response.items.length > 0) {
            this.currentSequence = response.sequence;
          }

          // Check if there are more items to load
          this.hasMoreData.set(response.items.length === this.pageSize);
          this.loading.set(false);
        },
        error: (error) => {
          console.error('Failed to load audit feed:', error);
          this.error.set('Unable to load activity history. Please try again.');
          this.loading.set(false);
        },
      });
  }

  /**
   * Load more audit feed items for pagination
   */
  loadMore(): void {
    if (this.loading() || this.loadingMore() || !this.hasMoreData()) return;

    const clientId = this.entity()?.id;
    const companyId = this.entity()?.owner?.id;

    if (isNullOrUndefined(clientId) || isNullOrUndefined(companyId)) return;

    this.loadingMore.set(true);

    this.feedService
      .getAuditFeedForEntity(
        companyId,
        clientId,
        this.currentSequence,
        'backward',
        this.pageSize,
      )
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          if (response.items.length > 0) {
            const transformedItems = this.transformAuditEventItems(
              response.items,
            );
            this.currentSequence = response.sequence;

            // Append to existing data, but filter out duplicates
            this.auditFeed.update((feed) => {
              const existingIds = new Set(feed.map((item) => item.id));
              const newItems = transformedItems.filter(
                (item) => !existingIds.has(item.id),
              );
              return [...feed, ...newItems];
            });

            // Check if there are more items to load
            this.hasMoreData.set(response.items.length === this.pageSize);
          } else {
            // No more data to load
            this.hasMoreData.set(false);
          }
          this.loadingMore.set(false);
        },
        error: (error) => {
          console.error('Failed to load more audit feed items:', error);
          this.loadingMore.set(false);
        },
      });
  }

  /**
   * Get the appropriate icon class for an event type
   * @param eventType The type of event (CREATE, UPDATE, DELETE)
   * @returns CSS classes for the event icon
   */
  getEventIcon(eventType: string): string {
    const eventIcons: Record<string, string> = {
      CREATE: 'pi pi-plus-circle text-success',
      UPDATE: 'pi pi-pencil text-warning',
      DELETE: 'pi pi-trash text-danger',
    };

    return eventIcons[eventType] || 'pi pi-info-circle text-info';
  }

  /**
   * Format a date string to display time only
   * @param dateStr The date string to format
   * @returns Formatted time string
   */
  formatTime(dateStr: string): string {
    return this.measurementDateTimeService.formatTime(
      new Date(dateStr),
      'HH:mm',
    );
  }

  /**
   * Format a date string to display full date and time
   * @param dateStr The date string to format
   * @returns Formatted date string
   */
  formatDate(dateStr: string): string {
    return new Date(dateStr).toLocaleString();
  }

  /**
   * Check if an audit feed item has change details
   * @param item The audit feed item to check
   * @returns True if the item has changes
   */
  hasChanges(item: AuditFeedItem): boolean {
    return isDefined(item.changes) && item.changes.length > 0;
  }
  protected override updateFormFields(): void {
    // No form fields to update in this section
  }

  protected override submitChanges(_clientDetails: Record<string, string>) {
    // No changes to submit in this section
  }

  private transformAuditEventItems(
    items: AuditEventResponse[],
  ): AuditFeedItem[] {
    return items.map((item) => ({
      id: item.id,
      date: item.date,
      owner: {
        id: item.owner.id,
        name: item.owner.name ?? '',
        type: item.owner.type ?? '',
      },
      eventClass: item.eventClass,
      eventType: item.eventType,
      user: {
        id: item.user.id,
        name: item.user.name ?? '',
      },
      entity: {
        id: item.entity.id,
        name: item.entity.name ?? '',
        type: item.entity.type ?? '',
      },
      changes: (item.changes ?? []).map((change: AuditEventChange) => ({
        action: change.action,
        field: change.field,
        name: change.name,
        oldValue: change.oldValue ?? { key: '', value: '' },
        newValue: change.newValue ?? { key: '', value: '' },
      })),
    }));
  }

  private groupItemsByDate(items: AuditFeedItem[]) {
    const grouped: Record<string, GroupedAuditFeed> = {};

    items.forEach((item) => {
      // Simplify date parsing
      const date = new Date(item.date);
      const dateKey = date.toISOString().split('T')[0]; // YYYY-MM-DD
      const formattedDate = date.toLocaleDateString('en-US', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
      });

      // Create or add to group
      if (isNullOrUndefined(grouped[dateKey])) {
        grouped[dateKey] = {
          date: dateKey,
          formattedDate: formattedDate,
          items: [],
        };
      }

      grouped[dateKey].items.push(item);
    });

    // Convert to array and sort by date (newest first)
    const result = Object.values(grouped).sort((a, b) =>
      b.date.localeCompare(a.date),
    );

    this.groupedAuditFeed.set(result);
  }
}
