import { Component, computed, effect, inject, input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ButtonModule } from 'primeng/button';

import {
  AccountsService,
  ClientResponse,
  EntitiesService,
} from '../../../../../api';
import {
  isBoolean,
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  APP_FEATURE_FLAGS,
  BACKEND_FEATURE_FLAGS,
  AppFeatureFlagDefaults,
  AppFeatureSection,
  AppListsTranslations,
  BackendFeatureSection,
  FormBuilderField,
  DEFAULT_SYSTEM_ID,
} from '../../../../../core/models';
import {
  createDropdownField,
  createListboxField,
  createModalListField,
  createNumberField,
  createTextAreaField,
  createTextField,
  FormFieldConfig,
  ListFieldModalConfig,
} from '../../../../../shared/models';
import { Validators } from '@angular/forms';
import { firstValueFrom } from 'rxjs';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';

interface ExternalTabData {
  title: string;
  url: string;
  icon: string;
  section: string;
  order: number;
}

@Component({
  selector: 'app-feature-section',
  imports: [CommonModule, ButtonModule, GridComponent, DynamicFormComponent],
  templateUrl: './feature-section.component.html',
  styleUrl: './feature-section.component.scss',
})
export class FeatureSectionComponent<
  T extends ClientResponse,
> extends EntitySectionBaseComponent<T> {
  feature = input<AppFeatureSection | BackendFeatureSection>();

  private readonly entitiesService = inject(EntitiesService);
  private readonly accountsService = inject(AccountsService);

  // Computed property to determine the correct feature bucket
  private readonly featureBucket = computed(() => {
    const section = this.feature();
    if (!section) return APP_FEATURE_FLAGS;

    // Check if this is a backend feature section by checking if it has defaults property
    if ('defaults' in section && typeof section.defaults === 'object') {
      return BACKEND_FEATURE_FLAGS;
    }

    return APP_FEATURE_FLAGS;
  });

  private readonly allFields = computed(() => {
    const section = this.feature();
    if (!section) return [];

    // Handle different field structures for app vs backend features
    if ('subfields' in section) {
      // This is an AppFeatureSection
      return [...(section.fields ?? []), ...(section.subfields ?? [])];
    } else {
      // This is a BackendFeatureSection
      return section.fields ?? [];
    }
  });

  private readonly inheritedFlags = computed(() => {
    const entity = this.entity();
    if (!entity) return {};

    if (
      'group' in entity &&
      typeof entity['group'] === 'string' &&
      entity['group']
    ) {
      return this.getCompanyGroupMergedFlags(entity['group']);
    }

    if (isDefined(entity?.['parent'])) {
      const parent = entity['parent'] as { id: string };
      if (parent.id !== 'root') {
        return this.getCompanyGroupMergedFlags(parent.id);
      }
    }

    return {};
  });

  readonly entityDetails = computed(() => {
    const entityDetails = this.entity();
    const fields = this.allFields();
    const bucket = this.featureBucket();
    const section = this.feature();
    const flags = entityDetails?.flags?.[bucket] as
      | Record<string, unknown>
      | undefined;
    const inherited = this.inheritedFlags() as Record<string, unknown>;

    if (isNullOrUndefined(entityDetails)) return [];

    const processedFields = fields
      .map((field) => {
        const value = flags?.[field.id];
        const inheritedValue = inherited[field.id];

        // Get default value from appropriate source
        let defaultValue: unknown;
        if (section && 'defaults' in section) {
          // Backend feature section
          defaultValue = section.defaults[field.id];
        } else {
          // App feature section
          defaultValue = AppFeatureFlagDefaults[field.id];
        }

        const isDefault = !isDefined(value) && !isDefined(inheritedValue);

        const defaultValueFormatted = !isEmpty(defaultValue)
          ? `${this.formatFeatureValue(defaultValue)} (Default)`
          : 'None';

        let displayValue: string;
        if (isDefined(value)) {
          displayValue = this.formatFeatureValue(value);
        } else if (isDefined(inheritedValue)) {
          displayValue = `${this.formatFeatureValue(
            inheritedValue,
          )} (Inherited)`;
        } else {
          if (isEmpty(defaultValue)) return null;
          displayValue = defaultValueFormatted;
        }

        return {
          key: field.title,
          value: displayValue,
          isDefault,
        };
      })
      .filter((field): field is NonNullable<typeof field> => field !== null);

    const pageField = processedFields.find((field) => field.key === 'Page');

    if (isDefined(pageField) && pageField.isDefault) {
      return [pageField].map(({ key, value }) => ({ key, value }));
    }

    return processedFields.map(({ key, value }) => ({ key, value }));
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '', transform: 'capitalize' },
    ];

    effect(() => {
      const section = this.feature();
      if (section) {
        // Handle different field structures for app vs backend features
        let fields: FormBuilderField[] = [];
        if ('subfields' in section) {
          // This is an AppFeatureSection
          fields = section.fields.concat(section.subfields ?? []) ?? [];
        } else {
          // This is a BackendFeatureSection
          fields = section.fields ?? [];
        }

        // Create an array of promises for fields that need lookup values
        const lookupPromises = fields
          .filter((field) => isDefined(field.valueLookup))
          .map((field) =>
            this.getLookupValues(field.valueLookup)
              .then((result) => {
                field.values = result;
                return field;
              })
              .catch(() => field),
          );

        // Wait for all lookups to complete, then update form
        if (lookupPromises.length > 0) {
          Promise.all(lookupPromises)
            .then(() => {
              this.updateFormFields();
            })
            .catch(() => {});
        } else {
          // No lookups needed, update form immediately
          this.updateFormFields();
        }
      }
    });
  }

  private formatFeatureValue(value: unknown): string {
    if (isBoolean(value)) {
      return value ? 'Enabled' : 'Disabled';
    }

    return value?.toString() ?? '';
  }

  private async getCompanyGroupMergedFlags(
    groupId: string,
  ): Promise<Record<string, unknown>> {
    const result: Record<string, unknown> = {};
    const groups: unknown[] = [];
    let currentGroupId: string | undefined = groupId;

    while (
      typeof currentGroupId === 'string' &&
      currentGroupId &&
      currentGroupId !== DEFAULT_SYSTEM_ID
    ) {
      try {
        const group: unknown = await firstValueFrom(
          this.accountsService.getCompanyGroup(currentGroupId),
        );
        groups.push(group);
        currentGroupId =
          (group as { parent?: { id: string } }).parent?.id !== 'root'
            ? (group as { parent?: { id: string } }).parent?.id
            : undefined;
      } catch (error) {
        console.error(`Failed to fetch company group ${currentGroupId}`, error);
        currentGroupId = undefined;
      }
    }

    const reversedGroups = groups.slice().reverse();
    reversedGroups.forEach((g: unknown) => {
      const bucket = this.featureBucket();
      Object.entries(
        (g as { flags: Record<string, Record<string, unknown>> })?.flags?.[
          bucket
        ] ?? {},
      ).forEach(([key, value]) => {
        result[key] = value;
      });
    });

    return result;
  }

  protected override updateFormFields(): void {
    const entity = this.entity();
    const section = this.feature();
    const bucket = this.featureBucket();

    // Handle different field structures for app vs backend features
    let fields: FormBuilderField[] = [];
    if (section && 'subfields' in section) {
      // This is an AppFeatureSection
      fields = section.fields.concat(section.subfields ?? []) ?? [];
    } else if (section) {
      // This is a BackendFeatureSection
      fields = section.fields ?? [];
    }

    this.formFields = fields.map((field) => {
      const validations = [];
      if (field.required ?? false) {
        validations.push({
          name: 'required',
          validator: Validators.required,
          message: `${field.title} is required`,
        });
      }
      if (isDefined(field.min)) {
        validations.push({
          name: 'minLength',
          validator: Validators.min(field.min),
          message: `${field.title} must be at least ${field.min}`,
        });
      }
      if (isDefined(field.max)) {
        validations.push({
          name: 'maxLength',
          validator: Validators.max(field.max),
          message: `${field.title} must be at most ${field.max}`,
        });
      }
      switch (field.type) {
        case 'dropdown':
          return createDropdownField(
            field.id,
            field.title,
            (field.values ?? []).map((value) => ({
              label: value.value ?? '',
              value: value.key ?? '',
            })),
            entity?.flags?.[bucket]?.[field.id] as unknown as string,
            {
              name: field.id,
              validations,
              props: {
                appendTo: 'body',
              },
              hint: field.hint,
            },
          );

        case 'number':
          return createNumberField(
            field.id,
            field.title,
            entity?.flags?.[bucket]?.[field.id] as unknown as number,
            {
              name: field.id,
              validations,
              hint: field.hint,
            },
          );

        case 'checklist':
          return createListboxField(
            field.id,
            field.title,

            [],
            (field.values ?? []).map((value) => ({
              label: value.value,
              value: value.key?.toString() ?? '',
            })),
            {
              name: field.id,
              validations,
              hint: field.hint,
              props: {
                appendTo: 'body',
                multiple: true,
                optionLabel: 'label',
                optionValue: 'value',
                style: { height: '250px' },
              },
            },
          );

        case 'list':
          if (field.id === 'page-external-tabs') {
            const externalTabModalConfig: ListFieldModalConfig = {
              modalComponent: ModalListFormComponent,
              modalTitle: 'External Tab',
              defaultItemProvider: (): ExternalTabData => ({
                title: '',
                url: '',
                icon: 'browser',
                section: '',
                order: 0,
              }),
              listItemFormatter: (item: unknown) => {
                const tabItem = item as ExternalTabData;
                return {
                  id: tabItem.title,
                  display: `${tabItem.title} (${tabItem.url})`,
                  icon: tabItem.icon,
                };
              },

              modalFields: (item?: unknown): FormFieldConfig[] => {
                const tabItem = item as ExternalTabData | undefined;
                return [
                  createTextField('title', 'Title', tabItem?.title ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'Title is required',
                      },
                    ],
                  }),
                  createTextField('url', 'URL', tabItem?.url ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'URL is required',
                      },
                    ],
                  }),
                  createTextField(
                    'icon',
                    'Icon',
                    tabItem?.icon ?? 'browser',
                    {},
                  ),
                  createTextField(
                    'section',
                    'Section',
                    tabItem?.section ?? '',
                    {
                      hint: AppListsTranslations['FIELDS']['SECTION_DESC'],
                    },
                  ),
                  createNumberField('order', 'Order', tabItem?.order ?? 0, {
                    hint: AppListsTranslations['FIELDS']['ORDER_DESC'],
                  }),
                ];
              },
              subHeader:
                AppListsTranslations['MODALS']['EXTERNAL-TABS']['DESC'],
            };

            return createModalListField(
              field.id,
              field.title,
              (entity?.flags?.[bucket]?.[field.id] as ExternalTabData[]) ?? [],
              {
                name: field.id,
                validations,
                hint: field.hint,
                props: { modalConfig: externalTabModalConfig },
              },
            );
          } else if (field.id === 'page-admin-customPanels') {
            const customPanelModalConfig: ListFieldModalConfig = {
              modalComponent: ModalListFormComponent,
              modalTitle: 'Custom Panel',
              defaultItemProvider: () => ({}),
              listItemFormatter: (item: unknown) => {
                const tabItem = item as ExternalTabData;
                return {
                  id: tabItem.title,
                  display: `${tabItem.title} (${tabItem.url})`,
                  icon: tabItem.icon,
                };
              },

              modalFields: (item?: unknown): FormFieldConfig[] => {
                const tabItem = item as ExternalTabData | undefined;
                return [
                  createTextField('title', 'Title', tabItem?.title ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'Title is required',
                      },
                    ],
                  }),
                  createTextField('url', 'URL', tabItem?.url ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'URL is required',
                      },
                    ],
                  }),
                ];
              },
              subHeader:
                AppListsTranslations['MODALS']['ADMIN-ENTITY-TABS']['DESC'],
            };

            return createModalListField(
              field.id,
              field.title,
              (entity?.flags?.[bucket]?.[field.id] as ExternalTabData[]) ?? [],
              {
                name: field.id,
                validations,
                hint: field.hint,
                props: { modalConfig: customPanelModalConfig },
              },
            );
          } else if (field.id === 'page-overview-customPanels') {
            const customPanelModalConfig: ListFieldModalConfig = {
              modalComponent: ModalListFormComponent,
              modalTitle: 'Custom Panel',
              defaultItemProvider: () => ({}),
              listItemFormatter: (item: unknown) => {
                const tabItem = item as ExternalTabData;
                return {
                  id: tabItem.title,
                  display: `${tabItem.title} (${tabItem.url})`,
                  icon: tabItem.icon,
                };
              },

              modalFields: (item?: unknown): FormFieldConfig[] => {
                const tabItem = item as ExternalTabData | undefined;
                return [
                  createTextField('title', 'Title', tabItem?.title ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'Title is required',
                      },
                    ],
                  }),
                  createTextField('url', 'URL', tabItem?.url ?? '', {
                    required: true,
                    validations: [
                      {
                        name: 'required',
                        validator: Validators.required,
                        message: 'URL is required',
                      },
                    ],
                  }),
                ];
              },
              subHeader:
                AppListsTranslations['MODALS']['OVERVIEW-TABS']['DESC'],
            };

            return createModalListField(
              field.id,
              field.title,
              (entity?.flags?.[bucket]?.[field.id] as ExternalTabData[]) ?? [],
              {
                name: field.id,
                validations,
                hint: field.hint,
                props: { modalConfig: customPanelModalConfig },
              },
            );
          } else {
            return createTextField(
              field.id,
              field.title,
              entity?.flags?.[bucket]?.[field.id] as unknown as string,
              {
                name: field.id,
                validations,
                hint: field.hint,
              },
            );
          }

        case 'memo':
          return createTextAreaField(
            field.id,
            field.title,
            entity?.flags?.[bucket]?.[field.id] as unknown as string,
            {
              name: field.id,
              layout: 'horizontal',
              labelWidth: '1/3',
            },
          );

        case 'text':
        default:
          return createTextField(
            field.id,
            field.title,
            entity?.flags?.[bucket]?.[field.id] as unknown as string,
            {
              name: field.id,
              validations,
              hint: field.hint,
            },
          );
      }
    });
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object>,
  ): void {
    const transformedData = { fields: formData };

    // Emit the transformed values
    this.formValueChange.emit(transformedData);
  }

  async getLookupValues(valueLookup: string | undefined) {
    const ownerId = this.entity()?.owner.id ?? '';
    switch (valueLookup) {
      case 'reports': {
        const result_1 = await firstValueFrom(
          this.entitiesService.listReportDefinitions(ownerId),
        );
        const reports = result_1.items.map((x) => {
          return {
            key: x.id,
            value: x.name,
          };
        });
        return reports.sort((a, b) => a.value.localeCompare(b.value));
      }

      case 'assetTypes': {
        const result_2 = await firstValueFrom(
          this.entitiesService.listAssetTypes(ownerId),
        );
        const assetTypes = result_2.items.map((x_1) => {
          return {
            key: x_1.id,
            value: x_1.name,
          };
        });
        return assetTypes.sort((a_1, b_1) =>
          a_1.value.localeCompare(b_1.value),
        );
      }

      case 'alert-actions': {
        const actions = [
          {
            key: 'request_video',
            value: 'Request Video',
          },
          {
            key: 'label_current_trip',
            value: 'Label Current Trip',
          },
        ];
        actions.sort((a, b) => a.value.localeCompare(b.value));
        return Promise.resolve(actions);
      }

      default:
        return Promise.resolve([]);
    }
  }
}
